//! flux-matmul-bench -- microbenchmark for the FLUX DiT Q8 matmul hot path.
//!
//! Builds synthetic Q8_0 weights at FLUX single-block-MLP dimensions and times
//! `mat_vec_q8_0_rows_shared`, the kernel that dominates the velocity forward
//! pass. Also checks numerical equivalence against a scalar reference so a
//! SIMD/parallel reorder can be proven visually-identical (last-bit-only diffs).
//!
//! This does NOT need the 17.9 GB FLUX knot — it reproduces the arithmetic
//! shape (rows=12288, cols=3072, tokens=256) of the heaviest layer so the
//! kernel speedup can be measured directly on this 16 GB machine.

use std::time::Instant;

use distributed_inference::math::{f16_to_f32, mat_vec_q8_0_rows_shared};

/// Encode f32 -> IEEE half (round-to-nearest-even, with overflow to inf and
/// subnormal handling). Mirrors the standard ggml f16 layout the decoder reads.
fn f32_to_f16(value: f32) -> u16 {
    let bits = value.to_bits();
    let sign = ((bits >> 16) & 0x8000) as u16;
    let exp = ((bits >> 23) & 0xff) as i32 - 127 + 15;
    let mant = bits & 0x007f_ffff;
    if exp <= 0 {
        if exp < -10 {
            return sign;
        }
        let mant = mant | 0x0080_0000;
        let shift = (14 - exp) as u32;
        let mut half = (mant >> shift) as u16;
        if (mant >> (shift - 1)) & 1 != 0 {
            half += 1;
        }
        return sign | half;
    } else if exp >= 0x1f {
        return sign | 0x7c00;
    }
    let mut half = sign | ((exp as u16) << 10) | ((mant >> 13) as u16);
    if mant & 0x1000 != 0 {
        half += 1;
    }
    half
}

/// Build a Q8_0-encoded weight matrix [rows x cols] from an f32 source, block
/// size 32, layout = [f16 scale][32 x i8] per block. Returns (q8_bytes, f32_ref).
fn build_q8(rows: usize, cols: usize, seed: u64) -> (Vec<u8>, Vec<f32>) {
    let bpr = cols.div_ceil(32);
    let mut q8 = Vec::with_capacity(rows * bpr * 34);
    let mut f32_ref = vec![0.0f32; rows * cols];
    let mut state = seed.wrapping_mul(0x9E37_79B9_7F4A_7C15).wrapping_add(1);
    let mut next = || {
        state ^= state << 13;
        state ^= state >> 7;
        state ^= state << 17;
        // map to [-1, 1)
        ((state >> 40) as f32 / (1u64 << 24) as f32) * 2.0 - 1.0
    };
    for r in 0..rows {
        for b in 0..bpr {
            let mut block = [0.0f32; 32];
            let mut amax = 0.0f32;
            for (j, v) in block.iter_mut().enumerate() {
                let c = b * 32 + j;
                *v = if c < cols { next() } else { 0.0 };
                if v.abs() > amax {
                    amax = v.abs();
                }
            }
            let scale = if amax > 0.0 { amax / 127.0 } else { 0.0 };
            let inv = if scale > 0.0 { 1.0 / scale } else { 0.0 };
            // f16 round-trip the scale so decode matches exactly.
            let scale_h = f32_to_f16(scale);
            let scale_dec = f16_to_f32(scale_h);
            q8.extend_from_slice(&scale_h.to_le_bytes());
            for (j, v) in block.iter().enumerate() {
                let qi = (v * inv).round().clamp(-127.0, 127.0) as i8;
                q8.push(qi as u8);
                let c = b * 32 + j;
                if c < cols {
                    f32_ref[r * cols + c] = scale_dec * qi as f32;
                }
            }
        }
    }
    (q8, f32_ref)
}

/// Lean Q8-only builder (no f32 reference) for the large cold-bandwidth sweep,
/// where materializing an f32 mirror would itself OOM the box.
fn build_q8_only(rows: usize, cols: usize, seed: u64) -> Vec<u8> {
    let bpr = cols.div_ceil(32);
    let mut q8 = vec![0u8; rows * bpr * 34];
    let mut state = seed.wrapping_mul(0x9E37_79B9_7F4A_7C15).wrapping_add(1);
    for r in 0..rows {
        for b in 0..bpr {
            let off = (r * bpr + b) * 34;
            // deterministic per-block pseudo values
            let mut amax = 0.0f32;
            let mut vals = [0.0f32; 32];
            for v in vals.iter_mut() {
                state ^= state << 13;
                state ^= state >> 7;
                state ^= state << 17;
                *v = ((state >> 40) as f32 / (1u64 << 24) as f32) * 2.0 - 1.0;
                if v.abs() > amax {
                    amax = v.abs();
                }
            }
            let scale = if amax > 0.0 { amax / 127.0 } else { 0.0 };
            let inv = if scale > 0.0 { 1.0 / scale } else { 0.0 };
            let scale_h = f32_to_f16(scale);
            q8[off..off + 2].copy_from_slice(&scale_h.to_le_bytes());
            for (j, v) in vals.iter().enumerate() {
                q8[off + 2 + j] = ((v * inv).round().clamp(-127.0, 127.0) as i8) as u8;
            }
        }
    }
    q8
}

/// Scalar reference matmul: out[t*n + r] = sum_c f32w[r,c] * xs[t*d + c].
fn ref_matmul(out: &mut [f32], xs: &[f32], w: &[f32], n: usize, d: usize, tokens: usize) {
    for t in 0..tokens {
        for r in 0..n {
            let mut acc = 0.0f64;
            for c in 0..d {
                acc += (w[r * d + c] * xs[t * d + c]) as f64;
            }
            out[t * n + r] = acc as f32;
        }
    }
}

fn build_x(tokens: usize, d: usize, seed: u64) -> Vec<f32> {
    let mut state = seed.wrapping_mul(0xD1B5_4A32_D192_ED03).wrapping_add(7);
    let mut next = || {
        state ^= state << 13;
        state ^= state >> 7;
        state ^= state << 17;
        ((state >> 40) as f32 / (1u64 << 24) as f32) * 2.0 - 1.0
    };
    (0..tokens * d).map(|_| next()).collect()
}

fn main() {
    let threads = rayon::current_num_threads();
    eprintln!("[bench] rayon threads = {threads}");

    // FLUX single-block MLP fc1: rows=12288, cols=3072, image tokens=256.
    let n = 12288usize;
    let d = 3072usize;
    let tokens = 256usize;

    eprintln!("[bench] building synthetic Q8 weights ({n}x{d}) ...");
    let (q8, f32w) = build_q8(n, d, 0xABCD_1234);
    let xs = build_x(tokens, d, 0x55AA_99CC);
    eprintln!("[bench] q8 bytes = {} ({:.1} MB)", q8.len(), q8.len() as f64 / 1e6);

    // Correctness check on a small slice (full ref is O(n*d*tokens) and slow).
    {
        let check_tokens = 2usize;
        let mut out_k = vec![0.0f32; check_tokens * n];
        mat_vec_q8_0_rows_shared(&mut out_k, &xs[..check_tokens * d], &q8, n, d, check_tokens);
        let mut ref_k = vec![0.0f32; check_tokens * n];
        ref_matmul(&mut ref_k, &xs[..check_tokens * d], &f32w, n, d, check_tokens);
        let mut max_abs = 0.0f32;
        let mut max_rel = 0.0f32;
        for (a, b) in out_k.iter().zip(ref_k.iter()) {
            let ad = (a - b).abs();
            if ad > max_abs {
                max_abs = ad;
            }
            let denom = b.abs().max(1e-6);
            let rd = ad / denom;
            if rd > max_rel {
                max_rel = rd;
            }
        }
        eprintln!("[bench] correctness vs scalar ref: max_abs={max_abs:.3e} max_rel={max_rel:.3e}");
        // f32 tree-reduction vs f64 reference: last-bit noise only. A real
        // corruption (wrong dequant / reorder bug) blows this up by orders of
        // magnitude, so 2e-2 cleanly separates "equivalent" from "broken".
        assert!(max_abs < 1e-2, "kernel diverged from reference (max_abs={max_abs:.3e})");
    }

    // Warm up the page cache / threads.
    let mut out = vec![0.0f32; tokens * n];
    mat_vec_q8_0_rows_shared(&mut out, &xs, &q8, n, d, tokens);

    // Time one fc1-shaped matmul, averaged.
    let iters = 5;
    let t0 = Instant::now();
    for _ in 0..iters {
        mat_vec_q8_0_rows_shared(&mut out, &xs, &q8, n, d, tokens);
    }
    let per_call = t0.elapsed().as_secs_f64() / iters as f64;
    let flop = 2.0 * n as f64 * d as f64 * tokens as f64;
    eprintln!(
        "[bench] fc1 matmul ({n}x{d}, {tokens} tok): {:.3} ms/call, {:.2} GFLOP/s",
        per_call * 1e3,
        flop / per_call / 1e9
    );

    // Extrapolate to a full velocity pass. Per single block the heavy Q8 matmuls
    // (in element-products) are roughly: q,k,v (3x 3072x3072) + mlp_fc1
    // (12288x3072) + out_proj (3072x(3072+12288)). Double blocks ~2x that. This
    // is a rough lower bound built from the dominant terms.
    let single_block_macs = (3.0 * 3072.0 * 3072.0    // q,k,v
        + 12288.0 * 3072.0                            // mlp
        + 3072.0 * (3072.0 + 12288.0))                // out proj
        * tokens as f64;
    let fc1_macs = n as f64 * d as f64 * tokens as f64;
    let single_blocks = 38.0;
    let double_blocks = 19.0;
    let est_pass_s =
        per_call * (single_block_macs * single_blocks + 2.0 * single_block_macs * double_blocks)
            / fc1_macs;
    eprintln!(
        "[bench] est. full velocity pass (rough, matmul-only): {:.1} s",
        est_pass_s
    );

    // ── Cold-bandwidth probe ────────────────────────────────────────────
    // The 40 MB fc1 weight stays L2/L3-resident across the 5 timed iters, so
    // the number above is the *cache-hot compute ceiling*. The REAL DiT reads
    // ~12.6 GB of distinct Q8 weight per pass that cannot stay resident on a
    // 16 GB machine — so each pass streams weights from RAM/mmap (cold). To see
    // that regime, allocate a large Q8 buffer (many distinct rows) and sweep it
    // ONCE so no row is re-read from cache. Gate behind an env var since it
    // wants ~10 GB RAM.
    if std::env::var("FLUX_BENCH_COLD").is_ok() {
        // ~10 GB of Q8 rows at d=3072: rows = 10e9 / (96*34).
        let gib: f64 = std::env::var("FLUX_BENCH_COLD_GIB")
            .ok()
            .and_then(|s| s.parse().ok())
            .unwrap_or(10.0);
        let bpr = d.div_ceil(32);
        let bytes_per_row = bpr * 34;
        let big_rows = ((gib * 1e9) as usize) / bytes_per_row;
        eprintln!(
            "[bench] COLD: building {:.1} GB Q8 ({big_rows} rows) — single uncached sweep ...",
            big_rows as f64 * bytes_per_row as f64 / 1e9
        );
        // Use tokens=1 for the cold sweep: weight-read bandwidth per row is
        // identical regardless of token count, and a big out buffer
        // (tokens*big_rows*4) would itself OOM a 16 GB box. We're measuring how
        // fast the kernel can STREAM distinct weight bytes, not token reuse.
        let cold_tokens = 1usize;
        let big_q8 = build_q8_only(big_rows, d, 0xFEED_BEEF);
        let big_xs = build_x(cold_tokens, d, 0x1357_9BDF);
        let mut big_out = vec![0.0f32; cold_tokens * big_rows];
        let t1 = Instant::now();
        mat_vec_q8_0_rows_shared(&mut big_out, &big_xs, &big_q8, big_rows, d, cold_tokens);
        let cold = t1.elapsed().as_secs_f64();
        let gbps = big_q8.len() as f64 / cold / 1e9;
        let cold_flop = 2.0 * big_rows as f64 * d as f64 * cold_tokens as f64;
        eprintln!(
            "[bench] COLD sweep: {:.2} s for {:.1} GB Q8 -> {:.2} GB/s, {:.2} GFLOP/s",
            cold,
            big_q8.len() as f64 / 1e9,
            gbps,
            cold_flop / cold / 1e9
        );
        // Real DiT weight volume per velocity pass ≈ 12.6 GB. Extrapolate the
        // pass time from the measured cold streaming rate.
        let dit_gb = 12.6;
        eprintln!(
            "[bench] => extrapolated cold velocity pass @ {:.1} GB / pass: {:.1} s",
            dit_gb,
            dit_gb * 1e9 / (big_q8.len() as f64 / cold)
        );
    }
}
